function bdg(color) {
  const m = { green: ["#dcfce7","#166534"], orange: ["#fff7ed","#9a3412"], red: ["#fee2e2","#991b1b"], blue: ["#eff6ff","#1d4ed8"] };
  return { padding: "2px 10px", borderRadius: 20, fontSize: 12, fontWeight: 700, background: m[color][0], color: m[color][1] };
}

