function Login({ onLogin, setView }) {
  const [email, setEmail] = useState(""); const [pass, setPass] = useState(""); const [err, setErr] = useState(""); const [load, setLoad] = useState(false);
  const submit = async () => {
    if (!email || !pass) { setErr("Completa email y contrasena."); return; }
    setLoad(true); setErr("");
    const data = await sbFetch("users", { query: `?email=eq.${encodeURIComponent(email)}&password=eq.${encodeURIComponent(pass)}&select=*` });
    if (Array.isArray(data) && data.length > 0) onLogin(data[0]);
    else setErr("Email o contrasena incorrectos.");
    setLoad(false);
  };
  return (
    <div style={{ minHeight: "80vh", display: "flex", alignItems: "center", justifyContent: "center", padding: 24, background: "#f7f9f7", fontFamily: font }}>
      <div style={{ background: "white", borderRadius: 20, padding: "44px 40px", width: "100%", maxWidth: 420, boxShadow: "0 8px 40px rgba(0,0,0,0.10)" }}>
        <div style={{ textAlign: "center", marginBottom: 32 }}>
          <Logo size={56} />
          <h2 style={{ fontWeight: 900, fontSize: 24, color: "#1a1f1a", margin: "14px 0 4px" }}>Bienvenido de vuelta</h2>
          <p style={{ color: "#6b7280", fontSize: 14 }}>Ingresa a tu cuenta de Elite Padel</p>
        </div>
        <div style={{ marginBottom: 16 }}><label style={lbl}>Email</label><input value={email} onChange={e => setEmail(e.target.value)} placeholder="tu@email.com" style={inp} /></div>
        <div style={{ marginBottom: 8 }}><label style={lbl}>Contrasena</label><input type="password" value={pass} onChange={e => setPass(e.target.value)} style={inp} onKeyDown={e => e.key === "Enter" && submit()} /></div>
        {err && <div style={{ color: "#dc2626", fontSize: 13, marginBottom: 12 }}>{err}</div>}
        <button onClick={submit} disabled={load} style={{ ...btn, opacity: load ? 0.7 : 1 }}>{load ? "Ingresando..." : "Ingresar"}</button>
        <div style={{ textAlign: "center", marginTop: 20, fontSize: 14, color: "#6b7280" }}>
          No tenes cuenta? <span onClick={() => setView("register")} style={{ color: "#1a6b3a", fontWeight: 700, cursor: "pointer" }}>Registrate</span>
        </div>
      </div>
    </div>
  );
}

function Register({ onLogin, setView }) {
  const [form, setForm] = useState({ name: "", email: "", phone: "", password: "", plan: "Plan 8 Clases" });
  const [err, setErr] = useState(""); const [load, setLoad] = useState(false);
  const submit = async () => {
    if (!form.name || !form.password) { setErr("Nombre y contrasena son obligatorios."); return; }
    setLoad(true); setErr("");
    const planObj = PLANS.find(p => p.name === form.plan) || PLANS[0];
    const data = await sbFetch("users", { method: "POST", body: { name: form.name, email: form.email || null, password: form.password, phone: form.phone || null, role: "student", plan: form.plan, classes_total: planObj.classes, classes_done: 0, notes: "" } });
    if (Array.isArray(data) && data.length > 0) onLogin(data[0]);
    else if (data && data.code === "23505") setErr("Ese email ya esta registrado.");
    else setErr("Error al crear la cuenta.");
    setLoad(false);
  };
  return (
    <div style={{ minHeight: "80vh", display: "flex", alignItems: "center", justifyContent: "center", padding: 24, background: "#f7f9f7", fontFamily: font }}>
      <div style={{ background: "white", borderRadius: 20, padding: "44px 40px", width: "100%", maxWidth: 440, boxShadow: "0 8px 40px rgba(0,0,0,0.10)" }}>
        <div style={{ textAlign: "center", marginBottom: 28 }}>
          <Logo size={52} />
          <h2 style={{ fontWeight: 900, fontSize: 24, color: "#1a1f1a", margin: "12px 0 4px" }}>Crear cuenta</h2>
          <p style={{ color: "#6b7280", fontSize: 14 }}>Unete a Elite Padel Academy</p>
        </div>
        {[["Nombre completo *","name","text"],["Email","email","email"],["Telefono","phone","text"],["Contrasena *","password","password"]].map(([l,k,t]) => (
          <div key={k} style={{ marginBottom: 14 }}><label style={lbl}>{l}</label><input type={t} value={form[k]} placeholder={l.replace(" *","")} onChange={e => setForm({...form,[k]:e.target.value})} style={inp} /></div>
        ))}
        <div style={{ marginBottom: 20 }}><label style={lbl}>Plan</label>
          <select value={form.plan} onChange={e => setForm({...form,plan:e.target.value})} style={inp}>
            {PLANS.map(p => <option key={p.name} value={p.name}>{p.name}</option>)}
          </select>
        </div>
        {err && <div style={{ color: "#dc2626", fontSize: 13, marginBottom: 12 }}>{err}</div>}
        <button onClick={submit} disabled={load} style={{ ...btn, opacity: load ? 0.7 : 1 }}>{load ? "Creando..." : "Crear mi cuenta"}</button>
        <div style={{ textAlign: "center", marginTop: 16, fontSize: 14, color: "#6b7280" }}>
          Ya tenes cuenta? <span onClick={() => setView("login")} style={{ color: "#1a6b3a", fontWeight: 700, cursor: "pointer" }}>Ingresar</span>
        </div>
      </div>
    </div>
  );
}

function MyAccount({ user }) {
  const [payments, setPayments] = useState([]); const [load, setLoad] = useState(true);
  useEffect(() => {
    sbFetch("payments", { query: `?user_id=eq.${user.id}&order=date.desc` }).then(d => { setPayments(Array.isArray(d) ? d : []); setLoad(false); });
  }, [user.id]);
  const pct = user.classes_total > 0 ? Math.round((user.classes_done / user.classes_total) * 100) : 0;
  const left = user.classes_total - user.classes_done;
  return (
    <div style={{ maxWidth: 800, margin: "0 auto", padding: "40px 20px", fontFamily: font }}>
      <h1 style={{ fontSize: 28, fontWeight: 900, color: "#1a1f1a", marginBottom: 6 }}>Mi cuenta</h1>
      <p style={{ color: "#6b7280", marginBottom: 28 }}>Hola, <b>{user.name}</b></p>
      {left <= 2 && left > 0 && (
        <div style={{ background: "#fff7ed", border: "1px solid #fed7aa", borderRadius: 12, padding: 16, marginBottom: 20 }}>
          <div style={{ fontWeight: 700, color: "#9a3412" }}>Atencion: te quedan solo {left} clase(s)</div>
          <div style={{ fontSize: 13, color: "#7c2d12", marginTop: 4 }}>Contacta a tu entrenador para renovar tu plan.</div>
        </div>
      )}
      {left <= 0 && (
        <div style={{ background: "#fef2f2", border: "1px solid #fca5a5", borderRadius: 12, padding: 16, marginBottom: 20 }}>
          <div style={{ fontWeight: 700, color: "#991b1b" }}>Tu plan vencio - completaste todas tus clases</div>
          <div style={{ fontSize: 13, color: "#7f1d1d", marginTop: 4 }}>Comunicate con tu entrenador para renovar.</div>
        </div>
      )}
      {user.notes && (
        <div style={{ background: "#e8f5ee", border: "1px solid #1a6b3a", borderRadius: 14, padding: 20, marginBottom: 20 }}>
          <div style={{ fontWeight: 700, color: "#1a6b3a", marginBottom: 8 }}>Nota de tu entrenador</div>
          <div style={{ fontSize: 14, color: "#1a1f1a", lineHeight: 1.7 }}>{user.notes}</div>
        </div>
      )}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))", gap: 16, marginBottom: 28 }}>
        <Card icon="🎾" label="Clases realizadas" value={`${user.classes_done} / ${user.classes_total}`} />
        <Card icon="📋" label="Plan actual" value={user.plan || "—"} />
        <Card icon="📊" label="Clases restantes" value={`${left} clases`} />
      </div>
      <div style={{ background: "white", borderRadius: 14, padding: 24, border: "1px solid #e5e7eb", marginBottom: 24 }}>
        <div style={{ fontWeight: 700, marginBottom: 10 }}>Progreso — {pct}%</div>
        <div style={{ background: "#e5e7eb", borderRadius: 99, height: 14, overflow: "hidden" }}>
          <div style={{ width: `${pct}%`, height: "100%", background: "linear-gradient(90deg,#1a6b3a,#2d8a52)", borderRadius: 99 }} />
        </div>
      </div>
      <div style={{ background: "white", borderRadius: 14, padding: 24, border: "1px solid #e5e7eb" }}>
        <div style={{ fontWeight: 700, marginBottom: 16, fontSize: 16 }}>Historial de pagos</div>
        {load ? <div style={{ color: "#6b7280" }}>Cargando...</div>
        : payments.length === 0 ? <div style={{ color: "#6b7280", fontSize: 14 }}>Sin pagos registrados.</div>
        : payments.map(p => (
          <div key={p.id} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 0", borderBottom: "1px solid #e5e7eb" }}>
            <div>
              <div style={{ fontWeight: 600, fontSize: 14 }}>{p.concept}</div>
              <div style={{ color: "#6b7280", fontSize: 12 }}>{p.date}</div>
            </div>
            <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
              <span style={{ fontWeight: 800, color: "#1a6b3a" }}>${Number(p.amount).toLocaleString()}</span>
              <span style={bdg("green")}>Pagado</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function Students() {
  const [students, setStudents] = useState([]); const [load, setLoad] = useState(true);
  const [sel, setSel] = useState(null); const [payments, setPayments] = useState([]);
  const [adding, setAdding] = useState(false); const [newPay, setNewPay] = useState({ amount: "", concept: "" });
  const [note, setNote] = useState(""); const [search, setSearch] = useState(""); const [saving, setSaving] = useState(false);

  const reload = () => sbFetch("users", { query: "?role=eq.student&order=name.asc" }).then(d => { setStudents(Array.isArray(d) ? d : []); setLoad(false); });
  useEffect(() => { reload(); }, []);

  const open = async s => {
    setSel(s); setNote(s.notes || ""); setAdding(false);
    const p = await sbFetch("payments", { query: `?user_id=eq.${s.id}&order=date.desc` });
    setPayments(Array.isArray(p) ? p : []);
  };

  const addClass = async () => {
    const nd = Math.min((sel.classes_done || 0) + 1, sel.classes_total || 8);
    await sbFetch("users", { method: "PATCH", query: `?id=eq.${sel.id}`, body: { classes_done: nd } });
    const u = { ...sel, classes_done: nd }; setSel(u); setStudents(prev => prev.map(s => s.id === sel.id ? u : s));
  };

  const addPay = async () => {
    if (!newPay.amount || !newPay.concept) return;
    setSaving(true);
    await sbFetch("payments", { method: "POST", body: { user_id: sel.id, date: new Date().toISOString().split("T")[0], amount: Number(newPay.amount), concept: newPay.concept, status: "Pagado" } });
    const p = await sbFetch("payments", { query: `?user_id=eq.${sel.id}&order=date.desc` });
    setPayments(Array.isArray(p) ? p : []); setNewPay({ amount: "", concept: "" }); setAdding(false); setSaving(false);
  };

  const saveNote = async () => {
    await sbFetch("users", { method: "PATCH", query: `?id=eq.${sel.id}`, body: { notes: note } });
    setSel({ ...sel, notes: note });
  };

  if (sel) {
    const left = sel.classes_total - sel.classes_done;
    const pct = sel.classes_total > 0 ? Math.round((sel.classes_done / sel.classes_total) * 100) : 0;
    return (
      <div style={{ maxWidth: 760, margin: "0 auto", padding: "32px 20px", fontFamily: font }}>
        <button onClick={() => { setSel(null); reload(); }} style={{ background: "none", border: "none", color: "#1a6b3a", cursor: "pointer", fontWeight: 700, fontSize: 14, marginBottom: 24, padding: 0 }}>← Volver</button>
        <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 28 }}>
          <div style={{ width: 52, height: 52, borderRadius: "50%", background: "#e8f5ee", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 900, fontSize: 20, color: "#1a6b3a" }}>{sel.name[0]}</div>
          <div>
            <h2 style={{ margin: 0, fontWeight: 900, fontSize: 22, color: "#1a1f1a" }}>{sel.name}</h2>
            <div style={{ color: "#6b7280", fontSize: 14 }}>{sel.email || "Sin email"}{sel.phone ? ` · ${sel.phone}` : ""}</div>
          </div>
          <div style={{ marginLeft: "auto" }}><span style={bdg(left <= 0 ? "red" : left <= 2 ? "orange" : "green")}>{left <= 0 ? "Vencido" : `${left} restantes`}</span></div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(140px,1fr))", gap: 14, marginBottom: 20 }}>
          <Card icon="📋" label="Plan" value={sel.plan || "—"} />
          <Card icon="🎾" label="Clases" value={`${sel.classes_done}/${sel.classes_total}`} />
          <Card icon="📊" label="Restantes" value={String(left)} />
        </div>
        <div style={{ background: "white", borderRadius: 14, padding: "14px 18px", border: "1px solid #e5e7eb", marginBottom: 20 }}>
          <div style={{ fontSize: 12, color: "#6b7280", marginBottom: 6 }}>Progreso — {pct}%</div>
          <div style={{ background: "#e5e7eb", borderRadius: 99, height: 10, overflow: "hidden" }}>
            <div style={{ width: `${pct}%`, height: "100%", background: "#1a6b3a", borderRadius: 99 }} />
          </div>
        </div>
        <div style={{ display: "flex", gap: 10, marginBottom: 20, flexWrap: "wrap" }}>
          <button onClick={addClass} style={{ background: "#1a6b3a", color: "white", border: "none", padding: "10px 18px", borderRadius: 8, cursor: "pointer", fontWeight: 700, fontSize: 14 }}>+ Registrar clase</button>
          <button onClick={() => setAdding(!adding)} style={{ background: "#c9a227", color: "#1a1f1a", border: "none", padding: "10px 18px", borderRadius: 8, cursor: "pointer", fontWeight: 700, fontSize: 14 }}>+ Registrar pago</button>
        </div>
        {adding && (
          <div style={{ background: "#fffbea", border: "1px solid #f0d98a", borderRadius: 12, padding: 20, marginBottom: 20 }}>
            <div style={{ fontWeight: 700, marginBottom: 12 }}>Nuevo pago</div>
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              <input placeholder="Concepto" value={newPay.concept} onChange={e => setNewPay({...newPay,concept:e.target.value})} style={{ ...inp, flex: 2, minWidth: 160 }} />
              <input type="number" placeholder="Monto" value={newPay.amount} onChange={e => setNewPay({...newPay,amount:e.target.value})} style={{ ...inp, flex: 1, minWidth: 90 }} />
              <button onClick={addPay} disabled={saving} style={{ background: "#1a6b3a", color: "white", border: "none", padding: "10px 16px", borderRadius: 8, cursor: "pointer", fontWeight: 700 }}>{saving ? "..." : "Guardar"}</button>
            </div>
          </div>
        )}
        <div style={{ background: "white", borderRadius: 14, padding: 20, border: "1px solid #e5e7eb", marginBottom: 20 }}>
          <div style={{ fontWeight: 700, marginBottom: 10 }}>Nota para el alumno (el alumno la puede ver)</div>
          <textarea value={note} onChange={e => setNote(e.target.value)} rows={3} style={{ width: "100%", border: "1px solid #e5e7eb", borderRadius: 8, padding: 10, fontSize: 14, resize: "vertical", boxSizing: "border-box" }} />
          <button onClick={saveNote} style={{ marginTop: 8, background: "#1a6b3a", color: "white", border: "none", padding: "8px 16px", borderRadius: 8, cursor: "pointer", fontWeight: 700, fontSize: 13 }}>Guardar nota</button>
        </div>
        <div style={{ background: "white", borderRadius: 14, padding: 20, border: "1px solid #e5e7eb" }}>
          <div style={{ fontWeight: 700, marginBottom: 14 }}>Historial de pagos</div>
          {payments.length === 0 ? <div style={{ color: "#6b7280", fontSize: 14 }}>Sin pagos.</div>
          : payments.map(p => (
            <div key={p.id} style={{ display: "flex", justifyContent: "space-between", padding: "11px 0", borderBottom: "1px solid #e5e7eb" }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 14 }}>{p.concept}</div>
                <div style={{ color: "#6b7280", fontSize: 12 }}>{p.date}</div>
              </div>
              <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
                <span style={{ fontWeight: 800, color: "#1a6b3a" }}>${Number(p.amount).toLocaleString()}</span>
                <span style={bdg("green")}>Pagado</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  const filtered = students.filter(s => s.name.toLowerCase().includes(search.toLowerCase()));
  return (
    <div style={{ maxWidth: 900, margin: "0 auto", padding: "40px 20px", fontFamily: font }}>
      <h1 style={{ fontSize: 28, fontWeight: 900, color: "#1a1f1a", marginBottom: 4 }}>Alumnos</h1>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24, flexWrap: "wrap", gap: 12 }}>
        <p style={{ color: "#6b7280", margin: 0 }}>{students.length} alumnos registrados</p>
        <input placeholder="Buscar alumno..." value={search} onChange={e => setSearch(e.target.value)} style={{ ...inp, width: "auto", minWidth: 200 }} />
      </div>
      {load ? <div style={{ textAlign: "center", padding: 60, color: "#6b7280" }}>Cargando...</div>
      : filtered.length === 0 ? <div style={{ textAlign: "center", padding: 60, color: "#6b7280" }}>No hay alumnos.</div>
      : (
        <div style={{ display: "grid", gap: 14 }}>
          {filtered.map(s => {
            const left = s.classes_total - s.classes_done;
            const pct = s.classes_total > 0 ? Math.round((s.classes_done / s.classes_total) * 100) : 0;
            return (
              <div key={s.id} onClick={() => open(s)} style={{ background: "white", borderRadius: 14, padding: "18px 22px", border: "1px solid #e5e7eb", cursor: "pointer", display: "flex", alignItems: "center", gap: 18, flexWrap: "wrap" }}>
                <div style={{ width: 44, height: 44, borderRadius: "50%", background: "#e8f5ee", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 900, fontSize: 18, color: "#1a6b3a" }}>{s.name[0]}</div>
                <div style={{ flex: 1, minWidth: 160 }}>
                  <div style={{ fontWeight: 800, fontSize: 15, color: "#1a1f1a" }}>{s.name}</div>
                  <div style={{ fontSize: 13, color: "#6b7280" }}>{s.plan || "—"}</div>
                </div>
                <div style={{ minWidth: 120 }}>
                  <div style={{ fontSize: 12, color: "#6b7280", marginBottom: 4 }}>{s.classes_done}/{s.classes_total} clases</div>
                  <div style={{ background: "#e5e7eb", borderRadius: 99, height: 6, overflow: "hidden" }}>
                    <div style={{ width: `${pct}%`, height: "100%", background: "#1a6b3a", borderRadius: 99 }} />
                  </div>
                </div>
                <span style={bdg(left <= 0 ? "red" : left <= 2 ? "orange" : "green")}>{left <= 0 ? "Vencido" : `${left} restantes`}</span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

function Payments() {
  const [pays, setPays] = useState([]); const [studs, setStuds] = useState([]); const [load, setLoad] = useState(true);
  useEffect(() => {
    Promise.all([
      sbFetch("payments", { query: "?order=date.desc" }),
      sbFetch("users", { query: "?role=eq.student" }),
    ]).then(([p, s]) => { setPays(Array.isArray(p) ? p : []); setStuds(Array.isArray(s) ? s : []); setLoad(false); });
  }, []);
  const total = pays.reduce((s, p) => s + Number(p.amount), 0);
  const expiring = studs.filter(s => { const l = s.classes_total - s.classes_done; return l > 0 && l <= 2; });
  const vencidos = studs.filter(s => s.classes_done >= s.classes_total);
  const sMap = Object.fromEntries(studs.map(s => [s.id, s.name]));
  return (
    <div style={{ maxWidth: 900, margin: "0 auto", padding: "40px 20px", fontFamily: font }}>
      <h1 style={{ fontSize: 28, fontWeight: 900, color: "#1a1f1a", marginBottom: 28 }}>Pagos y facturacion</h1>
      {load ? <div style={{ color: "#6b7280" }}>Cargando...</div> : (
        <>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))", gap: 16, marginBottom: 28 }}>
            <Card icon="💰" label="Total recaudado" value={`$${total.toLocaleString()}`} />
            <Card icon="👥" label="Activos" value={studs.filter(s => s.classes_done < s.classes_total).length} />
            <Card icon="⚠️" label="Por vencer" value={expiring.length} />
            <Card icon="🔴" label="Vencidos" value={vencidos.length} />
          </div>
          {expiring.length > 0 && (
            <div style={{ background: "#fff7ed", border: "1px solid #fed7aa", borderRadius: 12, padding: 16, marginBottom: 20 }}>
              <div style={{ fontWeight: 700, color: "#9a3412", marginBottom: 8 }}>Por vencer (1-2 clases restantes)</div>
              {expiring.map(s => <div key={s.id} style={{ fontSize: 14, color: "#7c2d12", marginBottom: 2 }}>{s.name} — {s.plan} — {s.classes_total - s.classes_done} clase(s)</div>)}
            </div>
          )}
          {vencidos.length > 0 && (
            <div style={{ background: "#fef2f2", border: "1px solid #fca5a5", borderRadius: 12, padding: 16, marginBottom: 20 }}>
              <div style={{ fontWeight: 700, color: "#991b1b", marginBottom: 8 }}>Planes vencidos</div>
              {vencidos.map(s => <div key={s.id} style={{ fontSize: 14, color: "#7f1d1d", marginBottom: 2 }}>{s.name} — {s.plan}</div>)}
            </div>
          )}
          <div style={{ background: "white", borderRadius: 14, padding: 24, border: "1px solid #e5e7eb" }}>
            <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 16 }}>Todos los pagos</div>
            {pays.length === 0 ? <div style={{ color: "#6b7280" }}>Sin pagos.</div>
            : pays.map((p, i) => (
              <div key={p.id || i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 0", borderBottom: "1px solid #e5e7eb" }}>
                <div>
                  <div style={{ fontWeight: 600 }}>{sMap[p.user_id] || "Alumno"}</div>
                  <div style={{ fontSize: 13, color: "#6b7280" }}>{p.concept} · {p.date}</div>
                </div>
                <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
                  <span style={{ fontWeight: 800, color: "#1a6b3a", fontSize: 16 }}>${Number(p.amount).toLocaleString()}</span>
                  <span style={bdg("green")}>Pagado</span>
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

function Community({ user }) {
  const [posts, setPosts] = useState([]); const [load, setLoad] = useState(true);
  const [caption, setCaption] = useState(""); const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null); const [uploading, setUploading] = useState(false);
  const [comments, setComments] = useState({}); const [newComment, setNewComment] = useState({});
  const [expanded, setExpanded] = useState(null);

  const loadPosts = async () => {
    const p = await sbFetch("posts", { query: "?order=created_at.desc&select=*" });
    setPosts(Array.isArray(p) ? p : []); setLoad(false);
  };
  useEffect(() => { loadPosts(); }, []);

  const onFile = e => {
    const f = e.target.files[0]; if (!f) return;
    setFile(f);
    const r = new FileReader(); r.onload = ev => setPreview(ev.target.result); r.readAsDataURL(f);
  };

  const uploadPost = async () => {
    if (!file && !caption) return;
    setUploading(true);
    let mediaUrl = null; let mediaType = "text";
    if (file) {
      const ext = file.name.split(".").pop();
      const path = `${Date.now()}_${user.id}.${ext}`;
      const res = await fetch(`${SUPABASE_URL}/storage/v1/object/media/${path}`, {
        method: "POST",
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, "Content-Type": file.type },
        body: file,
      });
      if (res.ok) {
        mediaUrl = `${SUPABASE_URL}/storage/v1/object/public/media/${path}`;
        mediaType = file.type.startsWith("video") ? "video" : "image";
      }
    }
    await sbFetch("posts", { method: "POST", body: { user_id: user.id, user_name: user.name, caption, media_url: mediaUrl, media_type: mediaType } });
    setCaption(""); setFile(null); setPreview(null); setUploading(false);
    loadPosts();
  };

  const loadComments = async postId => {
    const c = await sbFetch("comments", { query: `?post_id=eq.${postId}&order=created_at.asc` });
    setComments(prev => ({ ...prev, [postId]: Array.isArray(c) ? c : [] }));
    setExpanded(postId);
  };

  const addComment = async postId => {
    const text = newComment[postId]; if (!text || !text.trim()) return;
    await sbFetch("comments", { method: "POST", body: { post_id: postId, user_id: user ? user.id : 0, user_name: user ? user.name : "Visitante", content: text } });
    setNewComment(prev => ({ ...prev, [postId]: "" }));
    loadComments(postId);
  };

  return (
    <div style={{ maxWidth: 700, margin: "0 auto", padding: "40px 20px", fontFamily: font }}>
      <h1 style={{ fontSize: 28, fontWeight: 900, color: "#1a1f1a", marginBottom: 4 }}>Comunidad</h1>
      <p style={{ color: "#6b7280", marginBottom: 28 }}>Compartí fotos y videos de torneos, partidos y entrenamientos</p>

      {user && (
        <div style={{ background: "white", borderRadius: 16, padding: 24, border: "1px solid #e5e7eb", marginBottom: 32, boxShadow: "0 2px 12px rgba(0,0,0,0.06)" }}>
          <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 16 }}>Compartir momento</div>
          <textarea value={caption} onChange={e => setCaption(e.target.value)} placeholder="Contale a la comunidad..." rows={3}
            style={{ width: "100%", border: "1px solid #e5e7eb", borderRadius: 8, padding: 12, fontSize: 14, resize: "vertical", boxSizing: "border-box", marginBottom: 12 }} />
          {preview && (
            <div style={{ marginBottom: 12 }}>
              {file && file.type.startsWith("video")
                ? <video src={preview} controls style={{ width: "100%", borderRadius: 10, maxHeight: 300 }} />
                : <img src={preview} style={{ width: "100%", borderRadius: 10, maxHeight: 300, objectFit: "cover" }} alt="preview" />
              }
            </div>
          )}
          <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
            <label style={{ background: "#f7f9f7", border: "1px solid #e5e7eb", borderRadius: 8, padding: "10px 16px", cursor: "pointer", fontWeight: 600, fontSize: 14 }}>
              Adjuntar foto/video
              <input type="file" accept="image/*,video/*" onChange={onFile} style={{ display: "none" }} />
            </label>
            <button onClick={uploadPost} disabled={uploading || (!file && !caption)} style={{ background: "#1a6b3a", color: "white", border: "none", padding: "10px 20px", borderRadius: 8, cursor: "pointer", fontWeight: 700, fontSize: 14, opacity: uploading ? 0.7 : 1 }}>
              {uploading ? "Subiendo..." : "Publicar"}
            </button>
          </div>
        </div>
      )}

      {load ? <div style={{ textAlign: "center", padding: 40, color: "#6b7280" }}>Cargando...</div>
      : posts.length === 0 ? <div style={{ textAlign: "center", padding: 40, color: "#6b7280" }}>Aun no hay publicaciones. Se el primero!</div>
      : posts.map(p => (
        <div key={p.id} style={{ background: "white", borderRadius: 16, padding: 20, marginBottom: 20, border: "1px solid #e5e7eb", boxShadow: "0 2px 8px rgba(0,0,0,0.04)" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 12 }}>
            <div style={{ width: 40, height: 40, borderRadius: "50%", background: "#e8f5ee", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 800, color: "#1a6b3a" }}>{p.user_name[0]}</div>
            <div>
              <div style={{ fontWeight: 700, fontSize: 14 }}>{p.user_name}</div>
              <div style={{ fontSize: 12, color: "#6b7280" }}>{new Date(p.created_at).toLocaleDateString("es-AR", { day: "2-digit", month: "short", year: "numeric" })}</div>
            </div>
          </div>
          {p.caption && <p style={{ fontSize: 15, lineHeight: 1.6, marginBottom: 12, color: "#1a1f1a" }}>{p.caption}</p>}
          {p.media_url && (
            p.media_type === "video"
              ? <video src={p.media_url} controls style={{ width: "100%", borderRadius: 10, maxHeight: 400, marginBottom: 12 }} />
              : <img src={p.media_url} style={{ width: "100%", borderRadius: 10, maxHeight: 400, objectFit: "cover", marginBottom: 12 }} alt="post" />
          )}
          <div style={{ display: "flex", gap: 16, alignItems: "center", paddingTop: 8, borderTop: "1px solid #e5e7eb" }}>
            <button onClick={() => expanded === p.id ? setExpanded(null) : loadComments(p.id)} style={{ background: "none", border: "none", color: "#1a6b3a", cursor: "pointer", fontWeight: 600, fontSize: 13 }}>
              Comentarios
            </button>
            {p.media_url && (
              <a href={p.media_url} download target="_blank" rel="noreferrer" style={{ color: "#6b7280", fontSize: 13, textDecoration: "none" }}>Descargar</a>
            )}
          </div>
          {expanded === p.id && (
            <div style={{ marginTop: 12 }}>
              {(comments[p.id] || []).map(c => (
                <div key={c.id} style={{ display: "flex", gap: 8, marginBottom: 8 }}>
                  <div style={{ width: 32, height: 32, borderRadius: "50%", background: "#e8f5ee", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 12, color: "#1a6b3a", flexShrink: 0 }}>{c.user_name[0]}</div>
                  <div style={{ background: "#f7f9f7", borderRadius: 10, padding: "8px 12px", flex: 1 }}>
                    <div style={{ fontWeight: 700, fontSize: 12, marginBottom: 2 }}>{c.user_name}</div>
                    <div style={{ fontSize: 13 }}>{c.content}</div>
                  </div>
                </div>
              ))}
              {user && (
                <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
                  <input value={newComment[p.id] || ""} onChange={e => setNewComment(prev => ({ ...prev, [p.id]: e.target.value }))}
                    placeholder="Escribi un comentario..." style={{ ...inp, flex: 1 }}
                    onKeyDown={e => e.key === "Enter" && addComment(p.id)} />
                  <button onClick={() => addComment(p.id)} style={{ background: "#1a6b3a", color: "white", border: "none", padding: "0 16px", borderRadius: 8, cursor: "pointer", fontWeight: 700 }}>→</button>
                </div>
              )}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

